rules.pseudocode:
for each action a:
  if a == 'eat' and food_here:
    mu_MB[s][a] = p_hat.get((s,a,'food'), 0.5) * r_D_food + (1 - p_hat.get((s,a,'food'), 0.5)) * r_D_nofood
  elif a in ['move_up','move_down','move_left','move_right']:
    s_next = clamp_to_grid(apply_move(s, a))
    mu_MB[s][a] = c_step + gamma * max(mu_MF.get((s_next, a2), 0.0) for a2 in actions)
  else:
    mu_MB[s][a] = c_step

for each action a:
  if a == 'eat' and food_here:
    p_food = p_hat.get((s,a,'food'), 0.5)
    outcome_var = p_food * (r_D_food - mu_MB[s][a])**2 + (1 - p_food) * (r_D_nofood - mu_MB[s][a])**2
    sigma2_MB[s][a] = outcome_var + sigma2_obs_MB / (1 + N_MB.get((s,a), 0))
  else:
    sigma2_MB[s][a] = sigma2_obs_MB / (1 + N_MB.get((s,a), 0))

p_hat[(s,a,o_obs)] = p_hat.get((s,a,o_obs), 0.5) + alpha_T * (1.0 - p_hat.get((s,a,o_obs), 0.5))
for o != o_obs:
  p_hat[(s,a,o)] = p_hat.get((s,a,o), 0.5) + alpha_T * (0.0 - p_hat.get((s,a,o), 0.5))
